/// BTDropdown — composable dropdown molecule.
///
/// Handles overlay positioning internally using [OverlayPortal] +
/// [CompositedTransformTarget/Follower]. The caller provides items and
/// optionally a custom trigger widget.
///
/// ## Usage:
/// ```dart
/// // Default trigger (button with chevron)
/// BTDropdown<String>(
///   label: 'Select status',
///   items: const [
///     BTDropdownItem(value: 'todo',  label: 'To Do'),
///     BTDropdownItem(value: 'done',  label: 'Done'),
///   ],
///   onSelect: (v) => debugPrint('selected: $v'),
/// )
///
/// // Checkbox multi-select
/// BTDropdown<String>(
///   label: 'Assignees',
///   variant: BTDropdownListVariant.checkbox,
///   items: _items,
///   values: _selectedValues,
///   onMultiSelect: (vs) => setState(() => _selectedValues = vs),
/// )
///
/// // Custom trigger
/// BTDropdown<String>(
///   items: _items,
///   trigger: ({required toggle, required isOpen}) => IconButton(
///     icon: Icon(Icons.filter_list),
///     onPressed: toggle,
///   ),
/// )
/// ```
library;

import 'package:btech_ui/src/components/atoms/button/button.types.dart';
import 'package:btech_ui/src/components/atoms/button/button.widget.dart';
import 'package:btech_ui/src/components/atoms/dropdown_list/dropdown_list.types.dart';
import 'package:btech_ui/src/components/atoms/dropdown_list/dropdown_list.widget.dart';
import 'package:flutter/material.dart';

/// Builder callback for custom triggers.
///
/// [toggle] opens or closes the dropdown.
/// [isOpen] reflects the current visibility state.
typedef BTDropdownTriggerBuilder = Widget Function({
  required VoidCallback toggle,
  required bool isOpen,
});

/// A composable dropdown that positions [BTDropdownList] over its trigger.
///
/// For single-select variants ([BTDropdownListVariant.list],
/// [BTDropdownListVariant.combobox], [BTDropdownListVariant.radio]) the
/// overlay closes automatically after a selection. For
/// [BTDropdownListVariant.checkbox] it stays open (multi-select pattern).
class BTDropdown<T> extends StatefulWidget {
  const BTDropdown({
    required this.items,
    this.label,
    this.trigger,
    this.variant = BTDropdownListVariant.list,
    this.value,
    this.values,
    this.hasSearch = false,
    this.itemsFilter,
    this.emptyLabel = 'No result found.',
    this.onSelect,
    this.onMultiSelect,
    this.onOpen,
    this.onClose,
    super.key,
  });

  /// Items to display in the list.
  final List<BTDropdownItem<T>> items;

  /// Label for the default trigger button. Ignored when [trigger] is set.
  final String? label;

  /// Optional custom trigger. Receives a [toggle] callback and [isOpen] flag.
  /// When null, a [BTButton.secondaryWhite] with label + chevron is rendered.
  final BTDropdownTriggerBuilder? trigger;

  /// Visual layout of the dropdown list.
  final BTDropdownListVariant variant;

  /// Controlled single-select value (used to highlight the selected row).
  final T? value;

  /// Controlled multi-select values (checkbox variant).
  final List<T>? values;

  /// Show a search input inside the list.
  final bool hasSearch;

  /// Custom filter applied when [hasSearch] is true and the user types a query.
  /// Receives the full [items] list and the current query string; returns the
  /// filtered subset to display.
  ///
  /// When null, defaults to a case-insensitive [String.contains] match on
  /// [BTDropdownItem.label].
  ///
  /// ```dart
  /// itemsFilter: (items, query) => items
  ///     .where((i) =>
  ///         i.label.toLowerCase().contains(query) ||
  ///         i.value.toString().toLowerCase().startsWith(query))
  ///     .toList(),
  /// ```
  final List<BTDropdownItem<T>> Function(
    List<BTDropdownItem<T>> items,
    String query,
  )? itemsFilter;

  /// Text shown in the empty state.
  final String emptyLabel;

  /// Called when an item is selected (all single-select variants).
  final ValueChanged<T>? onSelect;

  /// Called with the updated list after a checkbox selection.
  final ValueChanged<List<T>>? onMultiSelect;

  /// Called when the dropdown opens.
  final VoidCallback? onOpen;

  /// Called when the dropdown closes.
  final VoidCallback? onClose;

  @override
  State<BTDropdown<T>> createState() => _BTDropdownState<T>();
}

class _BTDropdownState<T> extends State<BTDropdown<T>> {
  final _overlayController = OverlayPortalController();
  final _layerLink = LayerLink();
  // Shared TapRegion group so clicks on the trigger are NOT treated as
  // "outside" the dropdown — prevents the close→reopen double-fire.
  late final Object _tapGroupId = UniqueKey();
  String _searchQuery = '';

  bool get _isOpen => _overlayController.isShowing;

  void _open() {
    if (_isOpen) return;
    _overlayController.show();
    setState(() => _searchQuery = '');
    widget.onOpen?.call();
  }

  void _close() {
    if (!_isOpen) return;
    _overlayController.hide();
    setState(() {}); // rebuild trigger so isOpen updates (chevron rotates back)
    widget.onClose?.call();
  }

  void _toggle() => _isOpen ? _close() : _open();

  void _handleSelect(T value) {
    if (widget.variant == BTDropdownListVariant.checkbox) {
      // Multi-select: toggle value in the list.
      final current = List<T>.from(widget.values ?? []);
      if (current.contains(value)) {
        current.remove(value);
      } else {
        current.add(value);
      }
      widget.onMultiSelect?.call(current);
      widget.onSelect?.call(value);
      // Checkbox stays open.
    } else {
      widget.onSelect?.call(value);
      _close();
    }
  }

  /// Build items with checked state applied from [value]/[values].
  List<BTDropdownItem<T>> get _resolvedItems {
    return widget.items.map((item) {
      final isChecked = widget.variant == BTDropdownListVariant.checkbox
          ? (widget.values?.contains(item.value) ?? item.checked)
          : widget.variant == BTDropdownListVariant.radio
              ? (widget.value == item.value)
              : item.checked;
      return BTDropdownItem<T>(
        value: item.value,
        label: item.label,
        disabled: item.disabled,
        checked: isChecked,
        avatar: item.avatar,
        removable: item.removable,
      );
    }).toList();
  }

  List<BTDropdownItem<T>> get _filteredItems {
    if (!widget.hasSearch || _searchQuery.isEmpty) return _resolvedItems;
    if (widget.itemsFilter != null) {
      return widget.itemsFilter!(_resolvedItems, _searchQuery);
    }
    final q = _searchQuery.toLowerCase();
    return _resolvedItems
        .where((i) => i.label.toLowerCase().contains(q))
        .toList();
  }

  @override
  Widget build(BuildContext context) {
    return CompositedTransformTarget(
      link: _layerLink,
      child: OverlayPortal(
        controller: _overlayController,
        overlayChildBuilder: (ctx) => CompositedTransformFollower(
          link: _layerLink,
          targetAnchor: AlignmentDirectional.bottomStart
              .resolve(Directionality.of(context)),
          followerAnchor: AlignmentDirectional.topStart
              .resolve(Directionality.of(context)),
          offset: const Offset(0, 4),
          child: Align(
            alignment: AlignmentDirectional.topStart,
            child: TapRegion(
              groupId: _tapGroupId,
              onTapOutside: (_) => _close(),
              child: BTDropdownList<T>(
                variant: widget.variant,
                items: _filteredItems,
                hasSearch: widget.hasSearch,
                searchQuery: _searchQuery,
                emptyLabel: widget.emptyLabel,
                onSearch: widget.hasSearch
                    ? (q) => setState(() => _searchQuery = q)
                    : null,
                onSelect: _handleSelect,
              ),
            ),
          ),
        ),
        child: TapRegion(
          groupId: _tapGroupId,
          child: widget.trigger != null
              ? widget.trigger!(toggle: _toggle, isOpen: _isOpen)
              : _DefaultTrigger(
                  label: widget.label ?? 'Select',
                  isOpen: _isOpen,
                  onPressed: _toggle,
                ),
        ),
      ),
    );
  }
}

// ── Default trigger button ──────────────────────────────────────────────────

class _DefaultTrigger extends StatelessWidget {
  const _DefaultTrigger({
    required this.label,
    required this.isOpen,
    required this.onPressed,
  });

  final String label;
  final bool isOpen;
  final VoidCallback onPressed;

  @override
  Widget build(BuildContext context) {
    return BTButton(
      label: label,
      variant: BTButtonVariant.secondaryWhite,
      rightIcon: AnimatedRotation(
        duration: const Duration(milliseconds: 150),
        turns: isOpen ? 0.5 : 0.0,
        child: const Icon(Icons.keyboard_arrow_down_rounded, size: 20),
      ),
      onPressed: onPressed,
    );
  }
}
